files.content:
* { box-sizing: border-box; margin: 0; padding: 0; }
body { background: #f8fafc; font-family: sans-serif; }
.page { width: 375px; min-height: 812px; display: flex; flex-direction: column; }
.header { background: #ffffff; height: 56px; display: flex; align-items: center; padding: 0 16px; }
.title { font-size: 18px; font-weight: 700; color: #1e293b; }
.avatar-card { margin: 16px; background: #ffffff; border-radius: 12px; padding: 16px; display: flex; align-items: center; gap: 12px; }
.avatar { width: 64px; height: 64px; border-radius: 32px; background: #e2e8f0; }
.username { font-size: 16px; font-weight: 600; color: #0f172a; }
.settings-btn { margin: 0 16px; background: #3b82f6; color: #ffffff; border: none; border-radius: 8px; height: 44px; font-size: 14px; font-weight: 600; cursor: pointer; }
